import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import FruitContext from '../../contexts/FruitContext';

class LearnFruits extends Component {

  static contextType = FruitContext;

  state = {
      fruits : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.fruits} category="New Fruit" />
        )
    }
}

export default LearnFruits;