import React, { Component } from 'react'
import LearnAnimals from './LearnAnimals'
import LearnFruits from './LearnFruits'
import LearnHouseholdItems from './LearnHouseholdItems'

class LearnWords extends Component {

    render() {

        return (
        <div class="container">
            <div class="row mt-5">

                <LearnFruits />
                <LearnAnimals />
                <LearnHouseholdItems /> 
            </div>
        </div>
        )
    }
}

export default LearnWords;