import React, { Component } from 'react'
import TrueOrFalseExercisesContext from '../../../contexts/TrueOrFalseExercisesContext';
import ModelForTrueOrFalse from './ModelForTrueOrFalse'

class TrueOrFalseExercises extends Component {

    static contextType = TrueOrFalseExercisesContext;

    state = {
        trueOrFalseExercises : this.context,
    }

    render() {
        return (
            <div className="container">
                <div className="row mt-5 mb-5">

                    <div className="col-md-9">

                        <div className="tab-content">

                            {/* a1-mi-presento1 */}
                            <div className="tab-pane fade show active" id="a1-mi-presento1">
                                <ModelForTrueOrFalse db={this.state.trueOrFalseExercises.miPresento1} />
                            </div>

                            {/* a1-mi-presento2 */}
                            <div className="tab-pane fade" id="a1-mi-presento2">
                                <ModelForTrueOrFalse db={this.state.trueOrFalseExercises.miPresento2} />
                            </div>

                            {/* a1-mi-presento3 */}
                            <div className="tab-pane fade" id="a1-mi-presento3">
                                <ModelForTrueOrFalse db={this.state.trueOrFalseExercises.miPresento3} />
                            </div>

                            {/* a1-mi-presento4 */}
                            <div className="tab-pane fade" id="a1-mi-presento4">
                                <ModelForTrueOrFalse db={this.state.trueOrFalseExercises.miPresento4} />
                            </div>

                            {/* a1-mi-presento5 */}
                            <div className="tab-pane fade" id="a1-mi-presento5">
                                <ModelForTrueOrFalse db={this.state.trueOrFalseExercises.miPresento5} />
                            </div>

                            {/* a1-la-giornata-di-margherita */}
                            <div className="tab-pane fade" id="a1-la-giornata-di-margherita">
                                <ModelForTrueOrFalse db={this.state.trueOrFalseExercises.laGiornataDiMargherita} />
                            </div>
                        </div>   

                    </div>

                    <div className="col-md-3">

                        <div className="list-group" id="list-tab">

                            <h2>LEVEL A1</h2>
                            <hr />
                            {/* a1-mi-presento1 */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#a1-mi-presento1">{this.state.trueOrFalseExercises.miPresento1.title}</a>

                            {/* a1-mi-presento2 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#a1-mi-presento2">{this.state.trueOrFalseExercises.miPresento2.title}</a>

                            {/* a1-mi-presento3 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#a1-mi-presento3">{this.state.trueOrFalseExercises.miPresento3.title}</a>

                            {/* a1-mi-presento4 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#a1-mi-presento4">{this.state.trueOrFalseExercises.miPresento4.title}</a>

                            {/* a1-mi-presento5 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#a1-mi-presento5">{this.state.trueOrFalseExercises.miPresento5.title}</a>                                                        

                            {/* a1-la-giornata-di-margherita */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#a1-la-giornata-di-margherita">{this.state.trueOrFalseExercises.laGiornataDiMargherita.title}</a>

                            <h2 className="mt-5">LEVEL A2</h2>
                            <hr />

                        </div>

                    </div>

                </div>
            </div>
        )
    }
}

export default TrueOrFalseExercises;