import React, { Component } from 'react'

class CondizionalePresente extends Component {

    state = {
        ioAnswer : "",
        tuAnswer : "",
        luiLeiAnswer : "",
        noiAnswer : "",
        voiAnswer : "",
        loroAnswer : "",

        isIoAnswerStatus : false,
        isTuAnswerStatus : false,
        isLuiLeiAnswerStatus : false,
        isNoiAnswerStatus : false,
        isVoiAnswerStatus : false,
        isLoroAnswerStatus : false
    }

    showAnswers = () => {
        const verb = this.props.currentVerb;
        this.setState({
            ioAnswer : verb.condizionalePresente[0],
            tuAnswer : verb.condizionalePresente[1],
            luiLeiAnswer : verb.condizionalePresente[2],
            noiAnswer : verb.condizionalePresente[3],
            voiAnswer : verb.condizionalePresente[4],
            loroAnswer : verb.condizionalePresente[5],

            isIoAnswerStatus : true,
            isTuAnswerStatus : true,
            isLuiLeiAnswerStatus : true,
            isNoiAnswerStatus : true,
            isVoiAnswerStatus : true,
            isLoroAnswerStatus : true
        })
    }

    clearAnswers = () => {
        this.setState({
            ioAnswer : "",
            tuAnswer : "",
            luiLeiAnswer : "",
            noiAnswer : "",
            voiAnswer : "",
            loroAnswer : "",

            isIoAnswerStatus : false,
            isTuAnswerStatus : false,
            isLuiLeiAnswerStatus : false,
            isNoiAnswerStatus : false,
            isVoiAnswerStatus : false,
            isLoroAnswerStatus : false
        })
    }

    controlCondizionalePresenteIo = (e) => {
        this.setState({ ioAnswer : e.target.value })
        
        if(e.target.value === this.props.currentVerb.condizionalePresente[0]){
            this.setState({ isIoAnswerStatus : true })
        } else {
            this.setState({ isIoAnswerStatus : false })
        }
    }

    controlCondizionalePresenteTu = (e) => {
        this.setState({ tuAnswer : e.target.value })
        
        if(e.target.value === this.props.currentVerb.condizionalePresente[1]){
            this.setState({ isTuAnswerStatus : true })
        } else {
            this.setState({ isTuAnswerStatus : false })
        }
    }

    controlCondizionalePresenteLuiLei = (e) => {
        this.setState({ luiLeiAnswer : e.target.value })
        
        if(e.target.value === this.props.currentVerb.condizionalePresente[2]){
            this.setState({ isLuiLeiAnswerStatus : true })
        } else {
            this.setState({ isLuiLeiAnswerStatus : false })
        }
    }

    controlCondizionalePresenteNoi = (e) => {
        this.setState({ noiAnswer : e.target.value })
        
        if(e.target.value === this.props.currentVerb.condizionalePresente[3]){
            this.setState({ isNoiAnswerStatus : true })
        } else {
            this.setState({ isNoiAnswerStatus : false })
        }
    }

    controlCondizionalePresenteVoi = (e) => {
        this.setState({ voiAnswer : e.target.value })
        
        if(e.target.value === this.props.currentVerb.condizionalePresente[4]){
            this.setState({ isVoiAnswerStatus : true })
        } else {
            this.setState({ isVoiAnswerStatus : false })
        }
    }

    controlCondizionalePresenteLoro = (e) => {
        this.setState({ loroAnswer : e.target.value })
        
        if(e.target.value === this.props.currentVerb.condizionalePresente[5]){
            this.setState({ isLoroAnswerStatus : true })
        } else {
            this.setState({ isLoroAnswerStatus : false })
        }
    }

    render() {
        return (
        <div className="col-md-6 mb-5">
            <p><strong>Condizionale Presente</strong></p>

            <div className="input-group input-group-lg mb-4">
                <span className="input-group-text igt-width">Io</span>
                <input type="text" className="form-control" value={this.state.ioAnswer} onChange={this.controlCondizionalePresenteIo} />

                {
                    this.state.isIoAnswerStatus 
                    ? <span className="input-group-text answer-true"><i class="fas fa-check-circle"></i></span> 
                    : <span className="input-group-text answer-false"><i class="fas fa-times-circle"></i></span>
                }

            </div>

            <div className="input-group input-group-lg mb-4">
                <span className="input-group-text igt-width">Tu</span>
                <input type="text" className="form-control" value={this.state.tuAnswer} onChange={this.controlCondizionalePresenteTu} />

                {
                    this.state.isTuAnswerStatus 
                    ? <span className="input-group-text answer-true"><i class="fas fa-check-circle"></i></span> 
                    : <span className="input-group-text answer-false"><i class="fas fa-times-circle"></i></span>
                }

            </div>

            <div className="input-group input-group-lg mb-4">
                <span className="input-group-text igt-width">Lui/Lei</span>
                <input type="text" className="form-control" value={this.state.luiLeiAnswer} onChange={this.controlCondizionalePresenteLuiLei} />

                {
                    this.state.isLuiLeiAnswerStatus 
                    ? <span className="input-group-text answer-true"><i class="fas fa-check-circle"></i></span> 
                    : <span className="input-group-text answer-false"><i class="fas fa-times-circle"></i></span>
                }

            </div>

            <div className="input-group input-group-lg mb-4">
                <span className="input-group-text igt-width">Noi</span>
                <input type="text" className="form-control" value={this.state.noiAnswer} onChange={this.controlCondizionalePresenteNoi} />

                {
                    this.state.isNoiAnswerStatus 
                    ? <span className="input-group-text answer-true"><i class="fas fa-check-circle"></i></span> 
                    : <span className="input-group-text answer-false"><i class="fas fa-times-circle"></i></span>
                }

            </div>

            <div className="input-group input-group-lg mb-4">
                <span className="input-group-text igt-width">Voi</span>
                <input type="text" className="form-control" value={this.state.voiAnswer} onChange={this.controlCondizionalePresenteVoi} />

                {
                    this.state.isVoiAnswerStatus 
                    ? <span className="input-group-text answer-true"><i class="fas fa-check-circle"></i></span> 
                    : <span className="input-group-text answer-false"><i class="fas fa-times-circle"></i></span>
                }

            </div>

            <div className="input-group input-group-lg mb-4">
                <span className="input-group-text igt-width">Loro</span>
                <input type="text" className="form-control" value={this.state.loroAnswer} onChange={this.controlCondizionalePresenteLoro} />

                {
                    this.state.isLoroAnswerStatus 
                    ? <span className="input-group-text answer-true"><i class="fas fa-check-circle"></i></span> 
                    : <span className="input-group-text answer-false"><i class="fas fa-times-circle"></i></span>
                }

            </div>

            <button onClick={this.showAnswers} className="btn btn-primary">Show</button>
            <button onClick={this.clearAnswers} className="btn btn-primary float-end">Clear</button>
        </div>       
        )
    }
}

export default CondizionalePresente;