import React, { Component } from 'react'

class ModelForFillTheBlank extends Component {

    state = {
        id : 1,
        title : "Fill the blank - 1",
        sentences : [
            "Con gli ___ guardo la TV.", 
            "Con la ___ mangio la pizza.", 
            "Con le ___ ascolto la musica.", 
            "Con il ___ sento il profumo.",
            "Con le ___ abbraccio mio figlio.", 
            "Con i ___ mordo la mela.", 
            "Con la ___ penso", 
            "Con le ___ mani faccio tutti i lavori."
        ],
        answers : ["occhi", "bocca", "naso", "braccia", "denti", "testa", "mani", "capelli"],
        score : 0,
        show : false
    }

    checkAnswers = () => {

        this.clearScore()

        this.state.answers.forEach((answer, index) =>{
            const select = document.querySelector(`#answer${index+1} select`);
            if(this.state.answers[index] === select.options[select.selectedIndex].text){
                this.setState((state) => {                       
                    return {score: state.score + 1}
                });
            }
        })
    }

    showAnswers = () => {
        this.setState({
            show : true
        })
    }

    clearScore = () => {
        this.setState((state) => {                       
            return {score: 0}
        });
    }

    clearAnswer = () => {
        this.setState({
            show : false
        })
    }

    render() {

        const answers = <select class="form-select form-select-sm inline-select">
                            {
                                this.state.answers.map((answer, index) => (
                                    <option value={index}>{answer}</option>
                                ))
                            }
                        </select>

        return (
        <>
            <div className="overflow-auto">                
                <h2 className="float-start">{this.state.title}</h2>
                <h2 className="float-end">Scor : <span>{this.state.score}</span> / {this.state.answers.length}</h2>
            </div>
            <hr className="mb-4" />

            {/* {this.state.sentences.map((sentence, index) => (
                
                <p>{index + 1}. {sentence}</p>

            ))} */}

            <p>
                1. Con gli <span id="answer1">{answers}</span> guardo la TV. 
                {
                    this.state.show 
                    ? <span className="fill-the-blank-true-answer">({this.state.answers[0]})</span>
                    : null
                }
            </p>    

            <p>
                2. Con la <span id="answer2">{answers}</span> mangio la pizza.
                {
                    this.state.show 
                    ? <span className="fill-the-blank-true-answer">({this.state.answers[1]})</span>
                    : null
                }    
            </p>

            <p>
                3. Con le <span id="answer5">{answers}</span> ascolto la musica.
                {
                    this.state.show 
                    ? <span className="fill-the-blank-true-answer">({this.state.answers[2]})</span>
                    : null
                }    
            </p>

            <p>
                4. Con il <span id="answer6">{answers}</span> sento il profumo.
                {
                    this.state.show 
                    ? <span className="fill-the-blank-true-answer">({this.state.answers[3]})</span>
                    : null
                }    
            </p>

            <p>
                5. Con le <span id="answer7">{answers}</span> abbraccio mio figlio.
                {
                    this.state.show 
                    ? <span className="fill-the-blank-true-answer">({this.state.answers[4]})</span>
                    : null
                }  
            </p>

            <p>
                6. Con i <span id="answer8">{answers}</span> mordo la mela.
                {
                    this.state.show 
                    ? <span className="fill-the-blank-true-answer">({this.state.answers[5]})</span>
                    : null
                }    
            </p>

            <p>
                7. Con la <span id="answer9">{answers}</span> penso
                {
                    this.state.show 
                    ? <span className="fill-the-blank-true-answer">({this.state.answers[6]})</span>
                    : null
                }    
            </p>

            <p>
                8. Con le <span id="answer10">{answers}</span> mani faccio tutti i lavori.
                {
                    this.state.show 
                    ? <span className="fill-the-blank-true-answer">({this.state.answers[7]})</span>
                    : null
                }    
            </p>

            <hr />

            <button onClick={this.checkAnswers} className="btn btn-primary float-end ms-3">Check</button>
            <button onClick={this.showAnswers} className="btn btn-primary float-end ms-3">Show</button>
            <button onClick={this.clearAnswer} className="btn btn-primary float-end">Clear</button>

        </>
        )
    }
}

export default ModelForFillTheBlank;